render_header('Nueva contraseña',['robots'=>'noindex,nofollow']);?><section class="panel narrow"><h1>Nueva contraseña</h1><form method="post"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><input type="hidden" name="token" value="<?=e($token)?>"><label>Contraseña nueva<input type="password" name="password" minlength="10" required></label><button class="button">Guardar contraseña</button></form></section><?php render_footer();
